#include <stdio.h>
#include <string.h>
#include <ctype.h>
#include <limits.h>

int myAtoi(const char *s){
    int i=0, n=strlen(s);
    while(i<n && isspace((unsigned char)s[i])) i++;
    if(i==n) return 0;
    int sign=1;
    if(s[i]=='+'||s[i]=='-'){
        if(s[i]=='-') sign=-1;
        i++;
    }
    long long res=0;
    while(i<n && isdigit((unsigned char)s[i])){
        int d=s[i]-'0';
        if(sign==1){
            if(res> (INT_MAX - d)/10) return INT_MAX;
        }else{
            if(res> ((long long)INT_MAX +1 - d)/10) return INT_MIN;
        }
        res=res*10+d;
        i++;
    }
    return (int)(sign*res);
}

int main(){
    int T; 
    if(scanf("%d",&T)!=1) return 0;
    getchar(); // consume newline after T
    char buf[210];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(buf, sizeof(buf), stdin)) buf[0]='\0';
        buf[strcspn(buf,"\n")]='\0';
        printf("%d\n", myAtoi(buf));
    }
    return 0;
}

