import sys

def myAtoi(s: str) -> int:
    i=0; n=len(s)
    while i<n and s[i].isspace():
        i+=1
    if i==n:
        return 0
    sign=1
    if i<n and (s[i]=='+' or s[i]=='-'):
        if s[i]=='-': sign=-1
        i+=1
    res=0
    while i<n and s[i].isdigit():
        d=ord(s[i])-48
        if sign==1:
            if res> (2**31-1 - d)//10:
                return 2**31-1
        else:
            if res> (2**31 - d)//10:
                return -2**31
        res=res*10+d
        i+=1
    return sign*res

data=sys.stdin.read().splitlines()
if not data: sys.exit()
T=int(data[0].strip())
out=[]
for i in range(1, T+1):
    line=data[i] if i<len(data) else ''
    out.append(str(myAtoi(line)))
print('\n'.join(out))

