function myAtoi(s){
    let i=0, n=s.length;
    while(i<n && s[i]===' ') i++;
    if(i===n) return 0;
    let sign=1;
    if(s[i]==='+'||s[i]==='-'){
        if(s[i]==='-') sign=-1;
        i++;
